// Parse incoming Full Contact Data from ManyChat - v15
const raw = $input.first().json;
const body = raw.body || raw || {};

const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y'].includes(normalized);
};

const getCustomField = (fields, key) => {
  if (Array.isArray(fields)) {
    const hit = fields.find((item) => item?.name === key || item?.key === key || item?.field_name === key);
    return hit?.value ?? '';
  }
  if (fields && typeof fields === 'object') {
    return fields[key] ?? '';
  }
  return '';
};

const subscriberId = String(body.subscriber_id || body.id || '');
const message = String(body.message || body.last_input_text || '').trim();
const firstName = body.first_name || 'amigo';
const lastName = body.last_name || '';
const phone = body.whatsapp_phone || body.phone || '';
const timezone = body.timezone || '';
const subscribedAt = body.subscribed || body.subscribed_at || '';

const customFields = body.custom_fields || {};
const city = getCustomField(customFields, 'city');
const funnelStage = getCustomField(customFields, 'funnel_stage');
const interestedProduct = getCustomField(customFields, 'interested_product');
const isHumanActive = toBool(getCustomField(customFields, 'is_human_active'));

// Audio detection: ManyChat WhatsApp usually sends CDN URLs
const isAudio = message.startsWith('https://')
  && (message.includes('fbsbx.com') || message.includes('fbcdn.net') || message.includes('manybot-files.s3'));

// Empty message detection (customer opened chat without text)
const isEmpty = !message;

// Infer Salta from phone number (+549387 or +54387)
const normalizedPhone = String(phone).replace(/\s+/g, '');
const isSaltaPhone = normalizedPhone.startsWith('+549387')
  || normalizedPhone.startsWith('+54387')
  || normalizedPhone.startsWith('549387');

return [{
  json: {
    subscriber_id: subscriberId,
    first_name: firstName,
    last_name: lastName,
    phone,
    timezone,
    subscribed_at: subscribedAt,
    city,
    funnel_stage: funnelStage,
    interested_product: interestedProduct,
    is_human_active: isHumanActive,
    raw_message: message,
    is_audio: isAudio,
    is_empty: isEmpty,
    is_salta_phone: isSaltaPhone
  }
}];

// Merge: audio transcription or text input – v14
const detectData = $('Parse Input').first().json;
let userMessage, wasAudio;

try {
  const whisperOutput = $('Groq Whisper Transcribe').first().json;
  userMessage = whisperOutput.text || 'No pude entender el audio.';
  wasAudio = true;
} catch(e) {
  userMessage = detectData.raw_message;
  wasAudio = false;
}

return [{
  json: {
    ...detectData,
    user_message: userMessage,
    was_audio: wasAudio
  }
}];

// Wait 8 seconds so users can finish typing bursts (2-3 consecutive messages)
const data = $input.first().json;
await new Promise((resolve) => setTimeout(resolve, 8000));
return [{ json: data }];

