// --------------------------------------------------
// DEBOUNCE CHECK v15 - Atomic latest-message validation
// After debounce wait, continue only if this message is still latest
// --------------------------------------------------

const mergedData = $('Merge Input').first().json;
const saveNode = $('Save Incoming Message').first();

let ourId = null;
const savedBody = saveNode.json;

if (Array.isArray(savedBody)) {
  if (savedBody.length > 0 && savedBody[0]?.id !== undefined) {
    ourId = savedBody[0].id;
  }
} else if (savedBody && typeof savedBody === 'object') {
  if (savedBody.id !== undefined) {
    ourId = savedBody.id;
  }
}

if (ourId === null || ourId === undefined) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'could_not_extract_saved_message_id' } }];
}

const rpcResult = $('Check Is Latest (RPC)').first().json;

let isLatest = false;
if (typeof rpcResult === 'boolean') {
  isLatest = rpcResult;
} else if (Array.isArray(rpcResult) && rpcResult.length > 0) {
  isLatest = rpcResult[0] === true || rpcResult[0]?.check_is_latest_message === true;
} else if (rpcResult && typeof rpcResult === 'object') {
  isLatest = rpcResult.check_is_latest_message === true || rpcResult.result === true;
}

if (!isLatest) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'not_latest' } }];
}

return [{ json: { ...mergedData, should_continue: true, our_id: ourId } }];

// --------------------------------------------------
// MERGE & AGGREGATE recent user messages v15
// Consolidates burst messages from the last 40 seconds into one reply
// --------------------------------------------------

const mergedData = $('Debounce Check v14').first().json;

let recentRaw = [];
try {
  recentRaw = $('Fetch Recent Messages').all();
} catch (e) {
  recentRaw = [];
}

const byId = new Map();
for (const item of recentRaw) {
  const payload = item.json;
  const rows = Array.isArray(payload) ? payload : [payload];
  for (const row of rows) {
    if (!row || row.id === undefined || row.id === null) continue;
    byId.set(row.id, row);
  }
}

const recentMessages = [...byId.values()]
  .filter((row) => row.role === 'user')
  .sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

if (recentMessages.length <= 1) {
  return [{ json: { ...mergedData, messages_merged: 1 } }];
}

const combined = recentMessages
  .map((m) => String(m.message || '').trim())
  .filter((m) => m && m !== '(vacío)')
  .join(' ');

return [{
  json: {
    ...mergedData,
    user_message: combined || mergedData.user_message,
    messages_merged: recentMessages.length
  }
}];

// =============================================
// BUILD AI CONTEXT v17 - handoff consistency + product maps for image logic
// =============================================

if ($input.context.itemIndex > 0) return [];

const merged = $('Merge & Aggregate Messages').first().json;

// --- Customer Profile ---
let customerData = {};
try {
  const raw = $('Fetch Customer Profile').first().json;
  if (Array.isArray(raw) && raw.length > 0) customerData = raw[0];
  else if (raw && raw.manychat_id) customerData = raw;
} catch (e) {
  customerData = {};
}

// --- Conversation History ---
let historyRows = [];
try {
  const items = $('Fetch Conversation History').all();
  for (const item of items) {
    const d = item.json;
    if (Array.isArray(d)) historyRows.push(...d);
    else if (d && d.role && d.message) historyRows.push(d);
  }
} catch (e) {
  historyRows = [];
}

// --- Product Catalog + IMAGE/STOCK MAPS ---
let productRows = [];
let productImages = {};
let productKeyNameMap = {};
let productStockMap = {};

try {
  const items = $('Fetch Products').all();
  for (const item of items) {
    let d = item.json;
    if (d && d.data && Array.isArray(d.data)) d = d.data;

    const rows = Array.isArray(d) ? d : (d ? [d] : []);
    for (const p of rows) {
      if (!p || !p.product_key) continue;

      productRows.push(p);
      productKeyNameMap[p.product_key] = String(p.product_name || '').trim();
      productStockMap[p.product_key] = p.in_stock;

      const url = p.image_url || p.image || p.url;
      if (url && String(url).startsWith('http')) {
        productImages[p.product_key] = String(url).trim();
      }
    }
  }
} catch (e) {
  productRows = [];
}

// --- Human Active Check (ManyChat flag + DB flag) ---
const incomingHumanActive = merged.is_human_active === true;
const customerHumanAssigned = customerData.human_assigned === true;
const humanAssigned = incomingHumanActive || customerHumanAssigned;

if (humanAssigned) {
  return [{
    json: {
      skip_ai: true,
      reason: incomingHumanActive ? 'manychat_human_active' : 'customer_human_assigned',
      subscriber_id: merged.subscriber_id,
      first_name: merged.first_name,
      phone: merged.phone,
      user_message: merged.user_message,
      was_audio: merged.was_audio,
      customer_id: customerData.id || null,
      customer_profile: customerData,
      product_images: productImages,
      product_key_name_map: productKeyNameMap,
      product_stock_map: productStockMap
    }
  }];
}

// --- Format conversation history ---
historyRows.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
let historyText = '';
if (historyRows.length > 0) {
  historyText = historyRows.map((h) => {
    const role = h.role === 'user' ? 'CLIENTE' : h.role === 'bot' ? 'TECHNOBOT' : 'ASESOR HUMANO';
    const time = h.created_at
      ? new Date(h.created_at).toLocaleString('es-AR', { timeZone: 'America/Argentina/Salta' })
      : '';
    return `[${role}] ${time}: ${h.message}`;
  }).join('\n');
} else {
  historyText = '(Primera interacción con este cliente)';
}

// --- Customer profile summary ---
let profileText = '';
if (customerData.manychat_id) {
  const parts = [];
  if (customerData.city) parts.push(`Ciudad: ${customerData.city}`);
  if (customerData.is_salta_capital !== null && customerData.is_salta_capital !== undefined) {
    parts.push(`Salta Capital: ${customerData.is_salta_capital ? 'SÍ' : 'NO'}`);
  }
  if (customerData.preferred_brand) parts.push(`Marca preferida: ${customerData.preferred_brand}`);
  if (customerData.preferred_budget) parts.push(`Rango: ${customerData.preferred_budget}`);
  if (customerData.interested_product) parts.push(`Producto interés: ${customerData.interested_product}`);
  if (customerData.funnel_stage) parts.push(`Etapa: ${customerData.funnel_stage}`);
  parts.push(`Interacciones: ${customerData.total_interactions || 1}`);
  if (customerData.last_bot_interaction) {
    parts.push(`Última interacción: ${new Date(customerData.last_bot_interaction).toLocaleDateString('es-AR')}`);
  }
  profileText = parts.length > 0 ? parts.join(' | ') : '(Sin datos previos)';
} else {
  profileText = '(Cliente nuevo)';
}

const isFirstInteraction = historyRows.length === 0;

// --- Format product catalog ---
const productsByCategory = {};
for (const p of productRows) {
  const category = p.category || 'GENERAL';
  if (!productsByCategory[category]) productsByCategory[category] = [];

  const specs = [];
  if (p.ram_gb) specs.push(`${p.ram_gb}GB RAM`);
  if (p.storage_gb) specs.push(`${p.storage_gb}GB`);
  if (p.network) specs.push(String(p.network).toUpperCase());
  if (p.color) specs.push(p.color);

  const specsStr = specs.length > 0 ? ` (${specs.join(', ')})` : '';
  let line = `${p.product_name}${specsStr} — $${Number(p.price_ars).toLocaleString('es-AR')}`;
  if (p.promo_price_ars) line += ` | PROMO: $${Number(p.promo_price_ars).toLocaleString('es-AR')}`;
  if (p.price_usd) line += ` (USD ${p.price_usd})`;
  if (p.delivery_type === 'on_order') line += ` [A PEDIDO - ${p.delivery_days} días]`;
  if (p.in_stock === false) line += ' [SIN STOCK]';
  if (p.bancarizada_cuota) line += ` | Bancarizada 6c: $${Number(p.bancarizada_cuota).toLocaleString('es-AR')}`;
  if (p.macro_cuota) line += ` | Macro 6c: $${Number(p.macro_cuota).toLocaleString('es-AR')}`;
  productsByCategory[category].push(line);
}

let inventoryText = '';
for (const [cat, products] of Object.entries(productsByCategory)) {
  inventoryText += `\n[${cat}]\n`;
  inventoryText += products.join('\n');
  inventoryText += '\n';
}

const storePolicies = [
  'Pagos: transferencia en pesos, transferencia en dólares, Bitcoin y USDT (TRC-20) 0% recargo, efectivo en Salta Capital.',
  'No hacemos créditos personales.',
  'Envíos GRATIS a sucursal (BusPack/Flecha Carga, OCA o Vía Cargo), sin costo de despacho ni embalaje.',
  'Envíos a partir de 72 horas hábiles. Entrega presencial en Salta Capital en el día. Interior de Salta en 24 hs.'
].join('\n');

const chatInput = `[CLIENTE: ${merged.first_name}]
[MENSAJE ACTUAL: ${merged.user_message || '(mensaje vacío - el cliente abrió el chat)'}]
${merged.was_audio ? '[NOTA: El cliente envió un audio que fue transcripto]' : ''}
[ES PRIMERA INTERACCIÓN: ${isFirstInteraction ? 'SÍ' : 'NO'}]
[HORA ACTUAL: ${new Date().toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Salta',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
})}]

[POLÍTICAS TIENDA]\n${storePolicies}

[PERFIL DEL CLIENTE]
${profileText}

[HISTORIAL DE CONVERSACIÓN]
${historyText}

[INVENTARIO COMPLETO (${productRows.length} productos)]
${inventoryText}`;

return [{
  json: {
    skip_ai: false,
    chatInput,
    subscriber_id: merged.subscriber_id,
    first_name: merged.first_name,
    phone: merged.phone,
    user_message: merged.user_message,
    was_audio: merged.was_audio,
    customer_id: customerData.id || null,
    customer_profile: customerData,
    product_images: productImages,
    product_key_name_map: productKeyNameMap,
    product_stock_map: productStockMap
  }
}];

// Tool: info_tienda
// Fuente de verdad para datos de tienda, pagos y envíos
const query = $input.first().json.query || '';
const q = query.toLowerCase();

const info = {
  ubicacion: "📍 Caseros 1365, Salta Capital. Diagonal a OCA, enfrente del Sindicato de Camioneros.",
  horarios: "🕐 Lunes a Viernes: 10:00-13:00 y 18:00-21:00 | Sábados: 10:00-13:00 | Domingos: cerrado.",
  redes: "📱 Instagram y Facebook: @technostore.salta",
  pagos: "💳 Medios de pago: transferencia bancaria en pesos, transferencia en dólares (cotiza dólar crypto), Bitcoin y USDT (TRC-20) con 0% recargo, y efectivo en pesos o dólares (solo Salta Capital). ❌ No hacemos créditos personales.",
  envios: "📦 Envíos GRATIS a sucursal (BusPack/Flecha Carga, OCA o Vía Cargo). No cobramos despacho ni embalaje. El envío se realiza a partir de las 72 horas hábiles. En Salta Capital se coordina entrega presencial en el día. Interior de Salta: entregas en 24 hs.",
  tracking: "Siempre enviamos el número de seguimiento apenas despachamos para rastrear el paquete.",
  garantia: "Todos los equipos son nuevos con garantía oficial del fabricante."
};

let result = '';
if (q.includes('ubica') || q.includes('direcc') || q.includes('donde') || q.includes('dónde') || q.includes('local')) {
  result = info.ubicacion;
} else if (q.includes('horario') || q.includes('hora') || q.includes('abierto') || q.includes('atiend')) {
  result = info.horarios;
} else if (
  q.includes('pago') || q.includes('tarjeta') || q.includes('transfer') || q.includes('cripto') || q.includes('crypto')
  || q.includes('bitcoin') || q.includes('btc') || q.includes('usdt') || q.includes('trc20') || q.includes('efectivo')
  || q.includes('credito') || q.includes('crédito')
) {
  result = info.pagos;
} else if (q.includes('envío') || q.includes('envio') || q.includes('envía') || q.includes('envia') || q.includes('mandan') || q.includes('despacho') || q.includes('shipping')) {
  result = info.envios;
} else if (q.includes('seguimiento') || q.includes('tracking') || q.includes('rastreo') || q.includes('rastrear')) {
  result = info.tracking;
} else if (q.includes('instagram') || q.includes('face') || q.includes('red')) {
  result = info.redes;
} else if (q.includes('garantia') || q.includes('garantía')) {
  result = info.garantia;
} else {
  result = Object.values(info).join('\n');
}

return result;

// Tool: calcular_cuotas
// Regla comercial de cuotas (sin exponer identificadores internos)
const query = $input.first().json.query || '';
const q = String(query || '').toLowerCase();

let esSalta = null;
const saltaMatch = q.match(/salta[:\s]*(true|false|si|sí|no|unknown)/i);
if (saltaMatch) {
  const val = saltaMatch[1].toLowerCase();
  esSalta = (val === 'true' || val === 'si' || val === 'sí');
}

if (esSalta === false) {
  return 'Las cuotas son SOLO presenciales en Salta Capital. Para envíos a otras ciudades las opciones son transferencia bancaria (pesos o dólares), Bitcoin/USDT (0% recargo) o efectivo presencial. No se puede hacer cuotas por envío.';
}

if (esSalta === null) {
  return 'Necesito confirmar si estás en Salta Capital para calcular cuotas, porque las cuotas son solo presenciales en Salta Capital.';
}

const hasModelHint = /(iphone|samsung|redmi|poco|xiaomi|a\d{2}|s\d{2}|\d\+\d{3}|\b\d{2}\b)/i.test(query);
if (!hasModelHint) {
  return 'Para calcular cuotas exactas decime el modelo y la capacidad (por ejemplo: A56 8+256 o A56 12+256). No necesito códigos internos.';
}

return `Reglas de cuotas (cliente en Salta Capital):
- Cuotas disponibles SOLO presencial en Salta Capital
- 6 cuotas fijas (no hay 3, 9, 12 ni otras opciones)
- Opciones: Bancarizada 6 cuotas o Macro 6 cuotas (usá los montos del catálogo)
- NO aceptamos Naranja ni SubCrédito
- El cliente debe venir al local: Caseros 1365, Salta Capital
- Siempre destacar primero el precio de contado como opción principal`;

// Post-process AI response v18 + strict image rules + anti-internal-id guard + brand catalog splitting
const aiOutput = $input.first().json;
const mergedData = $('Merge & Aggregate Messages').first().json;
const contextData = $('Build AI Context').first().json;

const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s_-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const escapeRegExp = (value) => String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const parseProducts = (rawValue) => {
  const raw = String(rawValue ?? '').trim();
  if (!raw || raw.toLowerCase() === 'none') return [];

  const cleaned = raw
    .replace(/^\[/, '')
    .replace(/\]$/, '')
    .replace(/["']/g, '');

  const pieces = cleaned
    .split(/[,;|\n]/)
    .map((p) => p.trim().toLowerCase())
    .filter(Boolean)
    .filter((p) => p !== 'none')
    .filter((p) => /^[a-z0-9_-]+$/i.test(p));

  return [...new Set(pieces)];
};

const scoreToken = (token) => (/[a-z]*\d+[a-z]*/.test(token) ? 4 : 1);

const productImagesMap = contextData.product_images || {};
const productKeyNameMap = contextData.product_key_name_map || {};
const productStockMap = contextData.product_stock_map || {};

const catalog = Object.keys(productImagesMap).map((key) => ({
  key,
  keyNorm: normalize(key),
  name: String(productKeyNameMap[key] || key).trim(),
  nameNorm: normalize(productKeyNameMap[key] || ''),
  inStock: productStockMap[key],
  imageUrl: String(productImagesMap[key] || '').trim(),
}));

const keyAliasPairs = Object.entries(productKeyNameMap).flatMap(([key, name]) => {
  const human = String(name || key).trim();
  const variants = [key, key.replace(/_/g, '-'), key.replace(/-/g, '_')];
  return [...new Set(variants)].map((variant) => ({ alias: variant, human }));
});

const sanitizeInternalIds = (text) => {
  let out = String(text || '');

  out = out
    .replace(/\bError:\s*/gi, '')
    .replace(/product[_\s-]?keys?/gi, 'modelos')
    .replace(/c[oó]digos?\s+internos?/gi, 'modelos')
    .replace(/`([^`]+)`/g, '$1');

  for (const pair of keyAliasPairs) {
    const re = new RegExp(`\\b${escapeRegExp(pair.alias)}\\b`, 'gi');
    out = out.replace(re, pair.human);
  }

  // Any remaining long internal-style slug gets masked
  out = out.replace(/\b[a-z0-9]+(?:[-_][a-z0-9]+){3,}\b/gi, 'ese modelo');

  return out.replace(/\s{2,}/g, ' ').trim();
};

const resolveProductKey = (candidateRaw) => {
  const candidate = normalize(candidateRaw);
  if (!candidate) return null;

  const exact = catalog.find((p) => p.keyNorm === candidate);
  if (exact) return exact.key;

  const starts = catalog.filter((p) => p.keyNorm.startsWith(candidate));
  if (starts.length === 1) return starts[0].key;

  const partial = catalog
    .map((p) => {
      let score = 0;
      if (p.keyNorm.includes(candidate)) score += 5;
      if (p.nameNorm.includes(candidate)) score += 4;
      return { key: p.key, score };
    })
    .filter((x) => x.score > 0)
    .sort((a, b) => b.score - a.score || a.key.length - b.key.length);

  return partial.length > 0 ? partial[0].key : null;
};

const inferProductKeysFromText = (text, limit = 3) => {
  const t = normalize(text);
  if (!t) return [];

  const tokens = [...new Set(
    t.split(/\s+/)
      .map((w) => w.trim())
      .filter((w) => w.length >= 3 || /[a-z]*\d+[a-z]*/.test(w))
  )];

  const scored = catalog.map((p) => {
    let score = 0;

    if (t.includes(p.keyNorm)) score += 12;
    if (p.nameNorm && t.includes(p.nameNorm)) score += 10;

    for (const token of tokens) {
      const tokenScore = scoreToken(token);
      if (p.keyNorm.includes(token)) score += tokenScore;
      if (p.nameNorm.includes(token)) score += tokenScore;
    }

    if (p.inStock === false) score -= 2;
    return { key: p.key, score };
  });

  return scored
    .filter((x) => x.score >= 4)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map((x) => x.key);
};

const unique = (arr) => [...new Set(arr.filter(Boolean))];

let responseText = aiOutput.output || aiOutput.text || 'Disculpá, hubo un error. ¿Podés repetir tu consulta?';

const isSilent = responseText.trim() === '[SILENT]' || responseText.includes('[SILENT]');
if (isSilent) {
  return [{
    json: {
      is_silent: true,
      payload: null,
      needs_human: false,
      clean_text: '',
      metadata: { intent: 'followup', funnel_update: 'no_change', products: 'none' },
      products_list: [],
      subscriber_id: mergedData.subscriber_id,
      user_message: mergedData.user_message,
      was_audio: mergedData.was_audio,
      customer_id: contextData.customer_id,
      current_funnel_stage: contextData.customer_profile?.funnel_stage || null
    }
  }];
}

let metadata = {};
const metaMatch = responseText.match(/---METADATA---(.*?)---END_METADATA---/s);
if (metaMatch) {
  const metaLines = metaMatch[1].trim().split('\n');
  for (const line of metaLines) {
    const [key, ...valueParts] = line.split(':');
    if (key && valueParts.length > 0) {
      metadata[key.trim()] = valueParts.join(':').trim();
    }
  }
}

const needsHuman = responseText.includes('[HUMAN]');

let cleanText = responseText
  .replace(/---METADATA---[\s\S]*?---END_METADATA---/g, '')
  .replace(/\[HUMAN\]/g, '')
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .replace(/^#+\s/gm, '')
  .replace(/```[\s\S]*?```/g, '')
  .replace(/\s*[:：]?\s*products:\s*\[[^\]]*\]/gi, '')
  .replace(/\s*products:\s*\[[^\]]*\]/gi, '')
  .replace(/\s*products:\s*[^\n]+/gi, '')
  .replace(/en\s*\[info_tienda[^\]]*\]/gi, '📍 Caseros 1365, Salta Capital. Diagonal a OCA.')
  .replace(/\[info_tienda[^\]]*\]/gi, '📍 Caseros 1365, Salta Capital. Diagonal a OCA.')
  .replace(/\[calcular_cuotas[^\]]*\]/gi, '')
  .replace(/\[\w+_?\w*\s*:[^\]]*\]/g, '')
  .replace(/,?\s*en\s*\.\s*,?/gi, '. ')
  .replace(/\s{2,}/g, ' ')
  .trim();

cleanText = sanitizeInternalIds(cleanText);
if (!cleanText) cleanText = 'Disculpá, ¿me repetís la consulta?';

const MAX_CHARS = 1600;
const MAX_MESSAGES = 8;

const splitTextSafely = (text, maxChars = MAX_CHARS, maxMessages = MAX_MESSAGES) => {
  const normalized = String(text || '').replace(/\r/g, '').trim();
  if (!normalized) return [];

  const sentenceParts = normalized
    .split(/\n+/)
    .flatMap((part) => part.split(/(?<=[.!?])\s+/))
    .map((p) => p.trim())
    .filter(Boolean);

  const chunks = [];
  let current = '';

  const pushCurrent = () => {
    if (current && current.trim()) chunks.push(current.trim());
    current = '';
  };

  const appendPiece = (piece) => {
    if (!piece) return;
    if (!current) {
      current = piece;
      return;
    }
    if ((current.length + 1 + piece.length) <= maxChars) {
      current += ' ' + piece;
    } else {
      pushCurrent();
      current = piece;
    }
  };

  for (const part of sentenceParts) {
    if (part.length <= maxChars) {
      appendPiece(part);
      continue;
    }

    const words = part.split(/\s+/).filter(Boolean);
    let local = '';

    const pushLocal = () => {
      if (local) appendPiece(local.trim());
      local = '';
    };

    for (const word of words) {
      if (word.length > maxChars) {
        pushLocal();
        for (let i = 0; i < word.length; i += maxChars) {
          appendPiece(word.slice(i, i + maxChars));
        }
        continue;
      }

      if (!local) {
        local = word;
      } else if ((local.length + 1 + word.length) <= maxChars) {
        local += ' ' + word;
      } else {
        pushLocal();
        local = word;
      }
    }

    pushLocal();
  }

  pushCurrent();

  if (chunks.length <= maxMessages) return chunks;

  const trimmed = chunks.slice(0, maxMessages);
  const note = '... Si querés, te paso por marca (iPhone, Samsung o Redmi/POCO) para que sea más claro 👌';
  const last = trimmed[trimmed.length - 1] || '';
  const allowed = maxChars - note.length - 1;
  trimmed[trimmed.length - 1] = (allowed > 50 ? last.slice(0, allowed).trim() : last.slice(0, maxChars - 1).trim()) + '\n' + note;
  return trimmed;
};

const splitByBrandSections = (text) => {
  const headingRegex = /(iPhone:|Samsung:|Redmi\/POCO:|Redmi\/Poco:|Xiaomi:)/gi;
  const matches = [...String(text || '').matchAll(headingRegex)];
  if (matches.length < 2) return null;

  const sections = [];
  const intro = text.slice(0, matches[0].index).trim();
  if (intro) sections.push(intro);

  for (let i = 0; i < matches.length; i++) {
    const start = matches[i].index;
    const end = i + 1 < matches.length ? matches[i + 1].index : text.length;
    const section = text.slice(start, end).trim();
    if (section) sections.push(section);
  }

  return sections;
};

const userMsg = String(mergedData.user_message || '');
const explicitlyAskedForImage = /foto|fotos|imagen|imágen|imágenes|imagenes|mostrame|mostrá|ver.*(foto|imagen)|mandame|envíame|envia|quiero ver|photo|picture|foto del|foto de la/i.test(userMsg);
const askedFullCatalog = /(todos|todo el|catalogo completo|cat[aá]logo completo|lista completa|android y iphone|iphone y android|todas las marcas|ver todo|mostrar todo)/i.test(userMsg);

const metadataCandidates = parseProducts(metadata.products);
let normalizedProducts = metadataCandidates
  .map((candidate) => resolveProductKey(candidate))
  .filter(Boolean);

if (explicitlyAskedForImage && normalizedProducts.length === 0) {
  const inferredFromUser = inferProductKeysFromText(userMsg, 3);
  const inferredFromBot = inferProductKeysFromText(cleanText, 3);
  normalizedProducts = unique([...inferredFromUser, ...inferredFromBot]);
}

metadata.products = normalizedProducts.length > 0 ? normalizedProducts.join(', ') : 'none';

let textChunks = splitTextSafely(cleanText, MAX_CHARS, MAX_MESSAGES);
if (askedFullCatalog) {
  const sections = splitByBrandSections(cleanText);
  if (sections && sections.length >= 2) {
    const branded = [];
    for (const sec of sections) {
      const secChunks = splitTextSafely(sec, MAX_CHARS, 2);
      branded.push(...secChunks);
    }
    if (branded.length > 0) {
      textChunks = branded.slice(0, MAX_MESSAGES);
    }
  }
}

let messagesArray = textChunks.length > 0
  ? textChunks.map((chunk) => ({ type: 'text', text: sanitizeInternalIds(chunk) }))
  : [{ type: 'text', text: 'Disculpá, ¿me repetís la consulta?' }];

if (explicitlyAskedForImage && normalizedProducts.length === 0) {
  const profileKey = resolveProductKey(contextData.customer_profile?.interested_product || '');
  const inStockImageKeys = catalog
    .filter((p) => p.imageUrl && p.inStock !== false)
    .map((p) => p.key);
  const fallbackImageKeys = catalog.filter((p) => p.imageUrl).map((p) => p.key);

  const suggestionKeys = unique([
    profileKey,
    ...inStockImageKeys.slice(0, 6),
    ...fallbackImageKeys.slice(0, 6)
  ]).slice(0, 4);

  if (suggestionKeys.length > 0) {
    const suggestionNames = suggestionKeys.map((key) => {
      const item = catalog.find((p) => p.key === key);
      return item ? item.name : key;
    });

    const suggestionMsg = `\n\n📸 Tengo fotos de: ${suggestionNames.join(', ')}. Decime cuál querés y te la mando.`;
    if (!/tengo fotos de|no tengo fotos/i.test(cleanText)) {
      cleanText = sanitizeInternalIds(cleanText.trim() + suggestionMsg);
      const textItem = messagesArray.find((m) => m.type === 'text');
      if (textItem) textItem.text = cleanText;
    }
  } else {
    const noImgGeneric = '\n\n⚠️ Por ahora no tengo fotos cargadas para enviarte, pero te paso precio y detalles si querés.';
    if (!/no tengo|no tenemos/i.test(cleanText)) {
      cleanText = sanitizeInternalIds(cleanText.trim() + noImgGeneric);
      const textItem = messagesArray.find((m) => m.type === 'text');
      if (textItem) textItem.text = cleanText;
    }
  }
}

if (explicitlyAskedForImage && normalizedProducts.length > 0) {
  const sentNow = new Set();
  const keysWithoutImage = [];

  for (const key of normalizedProducts) {
    const item = catalog.find((p) => p.key === key);
    const imageUrl = item?.imageUrl || '';

    if (imageUrl && !sentNow.has(key)) {
      messagesArray.push({ type: 'image', url: imageUrl, image_url: imageUrl });
      sentNow.add(key);
    } else {
      keysWithoutImage.push(key);
    }
  }

  if (keysWithoutImage.length > 0 && !/no tengo|no tenemos/i.test(cleanText)) {
    const readable = keysWithoutImage.slice(0, 3).map((key) => {
      const item = catalog.find((p) => p.key === key);
      return item ? item.name : key;
    });
    const noImgNote = `\n\n⚠️ No tengo fotos de ${readable.join(', ')} por el momento. Si querés más info del modelo escribime.`;
    cleanText = sanitizeInternalIds(cleanText.trim() + noImgNote);
    const textItem = messagesArray.find((m) => m.type === 'text');
    if (textItem) textItem.text = cleanText;
  }
}

const payload = {
  subscriber_id: mergedData.subscriber_id,
  data: {
