const data = $('Process Response').first().json;
const metadata = data.metadata || {};
const products = Array.isArray(data.products_list) ? data.products_list : [];

const stageRank = {
  new: 0,
  browsing: 1,
  interested: 2,
  closing: 3,
  human_handoff: 4
};

const currentStage = String(data.current_funnel_stage || '').trim().toLowerCase();
const requestedStage = String(metadata.funnel_update || '').trim().toLowerCase();

const updates = {
  last_bot_interaction: new Date().toISOString(),
  updated_at: new Date().toISOString()
};

if (requestedStage && requestedStage !== 'no_change') {
  if (stageRank[requestedStage] !== undefined) {
    if (stageRank[currentStage] === undefined || stageRank[requestedStage] >= stageRank[currentStage]) {
      updates.funnel_stage = requestedStage;
    }
  }
}

if (metadata.city_detected && metadata.city_detected !== 'none') {
  let city = metadata.city_detected.trim();
  const lower = city.toLowerCase();
  if (['salta', 'salta capital', 'salta cap'].includes(lower)) {
    city = 'Salta Capital';
    updates.is_salta_capital = true;
  }
  updates.city = city;
}

if (metadata.is_salta === 'true') updates.is_salta_capital = true;
else if (metadata.is_salta === 'false') updates.is_salta_capital = false;

if (metadata.brand_interest && metadata.brand_interest !== 'none') updates.preferred_brand = metadata.brand_interest;
if (metadata.budget_hint && metadata.budget_hint !== 'none') updates.preferred_budget = metadata.budget_hint;
if (products.length > 0) updates.interested_product = products[0];

if (data.needs_human) {
  updates.human_assigned = true;
  updates.funnel_stage = 'human_handoff';
}

return [{ json: { subscriber_id: data.subscriber_id, updates } }];

