// Link the incoming conversation row to the upserted customer_id (best effort)
const upsertRaw = $input.first().json;

const toIntOrNull = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
};

const extractCustomerId = (raw) => {
  if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
  if (typeof raw === 'string') return toIntOrNull(raw);

  if (Array.isArray(raw) && raw.length > 0) {
    const first = raw[0];
    if (typeof first === 'number' && Number.isFinite(first)) return first;
    if (typeof first === 'string') return toIntOrNull(first);
    if (first && typeof first === 'object') {
      if (first.upsert_customer !== undefined && first.upsert_customer !== null) return toIntOrNull(first.upsert_customer);
      if (first.customer_id !== undefined && first.customer_id !== null) return toIntOrNull(first.customer_id);
      if (first.id !== undefined && first.id !== null) return toIntOrNull(first.id);
    }
  }

  if (raw && typeof raw === 'object') {
    if (raw.upsert_customer !== undefined && raw.upsert_customer !== null) return toIntOrNull(raw.upsert_customer);
    if (raw.customer_id !== undefined && raw.customer_id !== null) return toIntOrNull(raw.customer_id);
    if (raw.id !== undefined && raw.id !== null) return toIntOrNull(raw.id);
  }

  return null;
};

const customerId = extractCustomerId(upsertRaw);

const saveNode = $('Save Incoming Message').first();
const savedBody = saveNode.json;
let messageId = null;
if (Array.isArray(savedBody) && savedBody.length > 0) {
  messageId = savedBody[0]?.id;
} else if (savedBody && savedBody.id) {
  messageId = savedBody.id;
}

const parsedMessageId = toIntOrNull(messageId);
if (!Number.isFinite(customerId) || !Number.isFinite(parsedMessageId)) {
  return [];
}

return [{
  json: {
    message_id: parsedMessageId,
    customer_id: customerId
  }
}];
